const appointments = $input.item.json.data.items || [];
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setHours(0, 0, 0, 0);

const endOfTomorrow = new Date(tomorrow);
endOfTomorrow.setHours(23, 59, 59, 999);

const reminders = appointments.filter(apt => {
  const aptDate = new Date(apt.preferredDate);
  return aptDate >= tomorrow && aptDate <= endOfTomorrow && apt.status === 'CONFIRMED';
});

return reminders.map(apt => ({
  json: {
    appointmentId: apt.id,
    clientEmail: apt.client.email,
    clientName: `${apt.client.firstName} ${apt.client.lastName}`,
    date: apt.preferredDate,
    time: apt.preferredTime,
    referenceNumber: apt.referenceNumber
  }
}));
